const int mod = 1e9 + 7;
#include <bits/stdc++.h>
using namespace std;

int main() {
    int T;
    cin >> T;
    while (T--) {
        int n;
        cin >> n;
        vector<int> a(n);
        for (int i = 0; i < n; i++) {
            cin >> a[i];
        }
        sort(a.begin(), a.end(), greater<int>());

        map<int, int> cnt;
        for (int i = 0; i < n; i++) {
            cnt[a[i]]++;
        }

        vector<int> unique;
        for (auto& it : cnt) {
            unique.push_back(it.first);
        }

        int m = unique.size();
        vector<vector<long long>> dp(n + 1, vector<long long>(m + 1, 0));

        dp[0][0] = 1;

        for (int i = 1; i <= n; i++) {
            for (int j = 0; j <= m; j++) {
                if (j > 0) {
                    dp[i][j] += dp[i - 1][j - 1];
                    dp[i][j] %= mod;
                }
                dp[i][j] += dp[i - 1][j];
                dp[i][j] %= mod;
                if (cnt[unique[j - 1]] > 0) {
                    dp[i][j] += dp[i - cnt[unique[j - 1]]][j];
                    dp[i][j] %= mod;
                }
            }
        }

        long long ans = 0;
        for (int i = 0; i <= m; i++) {
            ans += dp[n][i];
            ans %= mod;
        }

        cout << ans << endl;
    }
    return 0;
}

