public class Main {
    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = sc.nextInt();
            }
            java.util.Arrays.sort(a);

            java.util.HashMap<Integer, Integer> cnt = new java.util.HashMap<>();
            for (int i = 0; i < n; i++) {
                cnt.put(a[i], cnt.getOrDefault(a[i], 0) + 1);
            }

            java.util.ArrayList<Integer> unique = new java.util.ArrayList<>();
            for (java.util.Map.Entry<Integer, Integer> it : cnt.entrySet()) {
                unique.add(it.getKey());
            }

            int m = unique.size();
            long[][] dp = new long[n + 1][m + 1];

            dp[0][0] = 1;

            for (int i = 1; i <= n; i++) {
                for (int j = 0; j <= m; j++) {
                    if (j > 0) {
                        dp[i][j] += dp[i - 1][j - 1];
                        dp[i][j] %= 1_000_000_007;
                    }
                    dp[i][j] += dp[i - 1][j];
                    dp[i][j] %= 1_000_000_007;
                    if (cnt.get(unique.get(j - 1)) > 0) {
                        dp[i][j] += dp[i - cnt.get(unique.get(j - 1))][j];
                        dp[i][j] %= 1_000_000_007;
                    }
                }
            }

            long ans = 0;
            for (int i = 0; i <= m; i++) {
                ans += dp[n][i];
                ans %= 1_000_000_007;
            }

            System.out.println(ans);
        }
    }
}

