const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});

readline.on('line', line => {
    if (line.length === 0) return;
    if (T === undefined) {
        T = parseInt(line);
        return;
    }
    n = parseInt(line);
    readline.once('line', line => {
        a = line.split(' ').map(Number);
        a.sort((a, b) => b - a);

        cnt = {};
        for (let i = 0; i < n; i++) {
            cnt[a[i]] = (cnt[a[i]] || 0) + 1;
        }

        unique = Object.keys(cnt).map(Number);
        m = unique.length;

        dp = Array(n + 1).fill(0).map(() => Array(m + 1).fill(0));
        dp[0][0] = 1;

        for (let i = 1; i <= n; i++) {
            for (let j = 0; j <= m; j++) {
                if (j > 0) {
                    dp[i][j] += dp[i - 1][j - 1];
                    dp[i][j] %= 1e9 + 7;
                }
                dp[i][j] += dp[i - 1][j];
                dp[i][j] %= 1e9 + 7;
                if (cnt[unique[j - 1]] > 0) {
                    dp[i][j] += dp[i - cnt[unique[j - 1]]][j];
                    dp[i][j] %= 1e9 + 7;
                }
            }
        }

        ans = 0;
        for (let i = 0; i <= m; i++) {
            ans += dp[n][i];
            ans %= 1e9 + 7;
        }

        console.log(ans);
        T--;
    });
});

